Actionscript.script:
onClipEvent (enterFrame) {
	自机 = _root.获得父节点(this, 5);
	if (自机.状态 == "兵器攻击")
	{
		if (random(10) == 0)
		{
			mp增加值 = 自机.mp满血值 / 10;
			mp增加上限 = 自机.mp满血值 * 2;
			if (自机.mp <= mp增加上限)
			{
				自机.mp += mp增加值;
			}
			else
			{
				自机.mp = mp增加上限;
			}
			_root.主角mp显示界面.刷新显示();
			//_root.效果("药剂动画",自机._x,自机._y,100);//
		}
	}
}

